prompt:
Review mode: baseline

Rules:
1. Review only added lines shown with a '+' marker.
2. Use the FILE path and numeric new-line labels exactly as supplied.
3. Report one root cause per issue. Do not duplicate findings.
4. Severity meanings: critical = immediate compromise/data loss; high = likely serious runtime
   or security failure; medium = conditional defect or important design violation; low = style
   or maintainability problem with limited runtime impact.
5. Confidence below 0.70 should normally be omitted.
6. Set citations to an empty array for every issue. Do not claim that a named standard or project rule requires something because no knowledge documents are supplied.
7. issue_id values must be sequential: ISSUE-001, ISSUE-002, ...
8. If no defensible issues exist, return an empty issues array.

Required JSON schema:
{
  "$defs": {
    "Citation": {
      "additionalProperties": false,
      "properties": {
        "source": {
          "description": "Knowledge document path shown in context",
          "title": "Source",
          "type": "string"
        },
        "section": {
          "description": "Section heading shown in context",
          "title": "Section",
          "type": "string"
        },
        "chunk_id": {
          "description": "Exact chunk identifier shown in context",
          "title": "Chunk Id",
          "type": "string"
        },
        "quote": {
          "description": "Short verbatim quote copied from the retrieved chunk",
          "maxLength": 400,
          "minLength": 1,
          "title": "Quote",
          "type": "string"
        }
      },
      "required": [
        "source",
        "section",
        "chunk_id",
        "quote"
      ],
      "title": "Citation",
      "type": "object"
    },
    "ReviewIssue": {
      "additionalProperties": false,
      "properties": {
        "issue_id": {
          "pattern": "^ISSUE-\\d{3}$",
          "title": "Issue Id",
          "type": "string"
        },
        "file": {
          "title": "File",
          "type": "string"
        },
        "line_start": {
          "minimum": 1,
          "title": "Line Start",
          "type": "integer"
        },
        "line_end": {
          "minimum": 1,
          "title": "Line End",
          "type": "integer"
        },
        "category": {
          "enum": [
            "correctness",
            "security",
            "reliability",
            "maintainability",
            "style",
            "architecture",
            "performance",
            "testing"
          ],
          "title": "Category",
          "type": "string"
        },
        "severity": {
          "$ref": "#/$defs/Severity"
        },
        "confidence": {
          "maximum": 1,
          "minimum": 0,
          "title": "Confidence",
          "type": "number"
        },
        "problem": {
          "minLength": 1,
          "title": "Problem",
          "type": "string"
        },
        "suggestion": {
          "minLength": 1,
          "title": "Suggestion",
          "type": "string"
        },
        "explanation": {
          "minLength": 1,
          "title": "Explanation",
          "type": "string"
        },
        "citations": {
          "items": {
            "$ref": "#/$defs/Citation"
          },
          "title": "Citations",
          "type": "array"
        }
      },
      "required": [
        "issue_id",
        "file",
        "line_start",
        "line_end",
        "category",
        "severity",
        "confidence",
        "problem",
        "suggestion",
        "explanation"
      ],
      "title": "ReviewIssue",
      "type": "object"
    },
    "Severity": {
      "enum": [
        "critical",
        "high",
        "medium",
        "low"
      ],
      "title": "Severity",
      "type": "string"
    }
  },
  "additionalProperties": false,
  "properties": {
    "summary": {
      "title": "Summary",
      "type": "string"
    },
    "issues": {
      "items": {
        "$ref": "#/$defs/ReviewIssue"
      },
      "title": "Issues",
      "type": "array"
    }
  },
  "required": [
    "summary",
    "issues"
  ],
  "title": "ReviewPayload",
  "type": "object"
}

External knowledge:
